<template>
  <div style="width: 40%; margin-left: 200px">
    <div style="margin-bottom: 50px; margin-left: 280px" >编辑留言</div>
    <el-form :model="ruleForm" :rules="rules" ref="ruleForm" label-width="200px">
      <el-form-item label="图书标准码" prop="bookNo">
        <el-cascader
            :props="{value: 'bookNo', label: 'bookNo'}"
            v-model="ruleForm.bookNos"
            :options="bookNos"
            @change="handleChange"></el-cascader>
      </el-form-item>
      <el-form-item label="用户id" prop="userId">
        <el-cascader
            :props="{value: 'id', label: 'id'}"
            v-model="ruleForm.sid"
            :options="sid"
            @change="handleChange"></el-cascader>
      </el-form-item>
      <el-form-item label="评论" prop="message">
        <el-input v-model="ruleForm.message"></el-input>
      </el-form-item>
    </el-form>
    <div style="margin-left: 290px; margin-top: 40px">
      <el-button type="primary" @click="save">提交</el-button>
    </div>
  </div>
</template>

<script>
import request from "@/utils/request";
//导入请求
export default {
  name: "EditPublish",
  data(){

    return {
      ruleForm: {},
      bookNos: [],
      sid: [],
      rules: {}
    }

  },
  created() {
    const id = this.$route.query.id
    console.log(id);
    request.get("/note/" + id).then(res =>{
      this.ruleForm = res.data
      //form改为ruleForm
    })
    request.get('/book/list').then(res => {
      this.bookNos = res.data;
    })
    request.get('/user/list').then(res => {
      this.sid = res.data
    })
  },
  methods: {
    save() {
      request.put('/note/update',this.ruleForm).then(res =>{
        if(res.code === '200'){
          this.$notify.success('更新成功')
          this.$router.push("/noteList")
        }else{
          this.$notify.error(res.msg)
        }
      })
      //    对接的是后台的UserController.java文件的路径
    },
    handleChange(){

    }
  }
}
</script>

